{
	title: "Updating stylesheet",
	async task() {
		const cssPath = config.resolvedPaths.tailwindCss;
		const cssSource = await fs.readFile(cssPath, "utf8");

		const modifiedCss = transformCss(cssSource, { css, cssVars });
		await fs.writeFile(cssPath, modifiedCss, "utf8");

		const relative = path.relative(cwd, cssPath);
		return `${highlight("Stylesheet")} updated at ${color.dim(relative)}`;
	},
}

&[data-selected="true"] {
  background-color: var(--toggle-button-bg-selected);
  color: var(--toggle-button-fg-selected);

  @media (hover: hover) {
    &:hover,
    &[data-hovered="true"] {
      background-color: var(--toggle-button-bg-selected-hover);
    }
  }

  &:active,
  &[data-pressed="true"] {
    background-color: var(--toggle-button-bg-selected-pressed);
  }
}

{
  ...preset,
  overrides: [
    {
      files: "./packages/styles/utilities/motions.css",
      options: {
        printWidth: 50,
      },
    },
  ],
  plugins: ["prettier-plugin-tailwindcss"],
  tailwindAttributes: ["className", "classNames"],
  tailwindFunctions: ["tv", "clsx", "cn"],
  tailwindStylesheet: path.resolve(import.meta.dirname, "./packages/styles/index.css"),
}

{
